import{_ as t,c as i,o as s,a1 as a}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Quick Start: Get Started in 5 Minutes | Superpowers Tutorial","description":"Install and experience Superpowers core functionality in 5 minutes, including installation, verification, and using your first command. Learn how Superpowers improves AI coding agent development efficiency.","frontmatter":{"title":"Quick Start: Get Started in 5 Minutes | Superpowers Tutorial","sidebarTitle":"5 Minute Quick Start","subtitle":"Quick Start: Get Started with Superpowers in 5 Minutes","description":"Install and experience Superpowers core functionality in 5 minutes, including installation, verification, and using your first command. Learn how Superpowers improves AI coding agent development efficiency.","tags":["Quick Start","Getting Started","Installation"],"order":20},"headers":[],"relativePath":"obra/superpowers/start/quick-start/index.md","filePath":"obra/superpowers/start/quick-start/index.md"}'),r={name:"obra/superpowers/start/quick-start/index.md"};function o(n,e,l,p,d,u){return s(),i("div",null,[...e[0]||(e[0]=[a(`<h1 id="quick-start-get-started-in-5-minutes" tabindex="-1">Quick Start: Get Started in 5 Minutes <a class="header-anchor" href="#quick-start-get-started-in-5-minutes" aria-label="Permalink to &quot;Quick Start: Get Started in 5 Minutes&quot;">​</a></h1><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><p>By the end of this chapter, you will:</p><ul><li>Complete Superpowers installation in 5 minutes</li><li>Verify the plugin is correctly loaded</li><li>Experience AI agent&#39;s new capabilities with the first core command</li></ul><hr><h2 id="your-current-struggles" tabindex="-1">Your Current Struggles <a class="header-anchor" href="#your-current-struggles" aria-label="Permalink to &quot;Your Current Struggles&quot;">​</a></h2><p>When using AI to write code, have you encountered these problems:</p><ul><li>AI skips design and starts writing code directly, making repeated changes without getting it right</li><li>Discover logic errors after writing a pile of code, wasting half an hour</li><li>No tests, bugs found only after going live</li><li>AI is lazy and skips TDD, resulting in unstable code quality</li></ul><p><strong>Superpowers solves these problems</strong>—it&#39;s not for &quot;smarter AI,&quot; it&#39;s for &quot;obedient AI.&quot; It enforces best practices through mandatory workflows.</p><hr><h2 id="when-to-use-this-approach" tabindex="-1">When to Use This Approach <a class="header-anchor" href="#when-to-use-this-approach" aria-label="Permalink to &quot;When to Use This Approach&quot;">​</a></h2><p>Any time you want AI to write code:</p><ul><li>✅ Build new features</li><li>✅ Fix bugs</li><li>✅ Refactor code</li><li>✅ Write tests</li></ul><p>Superpowers automatically checks task types and triggers the appropriate skill workflow.</p><hr><h2 id="🎒-prerequisites" tabindex="-1">🎒 Prerequisites <a class="header-anchor" href="#🎒-prerequisites" aria-label="Permalink to &quot;🎒 Prerequisites&quot;">​</a></h2><h3 id="platform-selection" tabindex="-1">Platform Selection <a class="header-anchor" href="#platform-selection" aria-label="Permalink to &quot;Platform Selection&quot;">​</a></h3><p>Superpowers supports three major AI coding platforms:</p><table tabindex="0"><thead><tr><th>Platform</th><th>Installation Difficulty</th><th>Recommended</th></tr></thead><tbody><tr><td>Claude Code</td><td>⭐ Easiest</td><td>✅ Recommended for beginners</td></tr><tr><td>OpenCode</td><td>⭐⭐⭐ Moderate</td><td>Advanced users</td></tr><tr><td>Codex</td><td>⭐⭐⭐ Complex</td><td>Requires CLI experience</td></tr></tbody></table><p><strong>This tutorial uses Claude Code</strong> because it has a built-in plugin marketplace for fastest installation.</p><h3 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h3><ul><li><a href="https://claude.ai/code" target="_blank" rel="noreferrer">Claude Code</a> installed</li><li>GitHub account (for plugin marketplace)</li><li>Basic terminal usage knowledge</li></ul><hr><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><p>What is Superpowers?</p><p><strong>Simply put</strong>: A package of &quot;enforced best practices&quot; skills.</p><p><strong>How it works</strong>: Before you let AI write code, it <strong>won&#39;t</strong> start writing directly. Instead, it:</p><ol><li><strong>Asks you questions first</strong> (brainstorming) — clarifies what you want to do</li><li><strong>Writes a plan</strong> (writing-plans) — breaks tasks into 2-5 minute chunks</li><li><strong>Develops with TDD</strong> (test-driven-development) — writes tests first, then code</li><li><strong>Reviews code</strong> (requesting-code-review) — checks quality every step</li></ol><p><strong>This is not a suggestion, it&#39;s a mandatory rule</strong> — skills trigger automatically, and AI must follow them.</p><hr><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-register-plugin-marketplace" tabindex="-1">Step 1: Register Plugin Marketplace <a class="header-anchor" href="#step-1-register-plugin-marketplace" aria-label="Permalink to &quot;Step 1: Register Plugin Marketplace&quot;">​</a></h3><p>Open Claude Code and enter:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> marketplace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> obra/superpowers-marketplace</span></span></code></pre></div><p><strong>Why</strong></p><p>Register the plugin marketplace so Claude Code knows where to find Superpowers plugins.</p><p><strong>You should see</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>✅ Successfully added marketplace: obra/superpowers-marketplace</span></span></code></pre></div><hr><h3 id="step-2-install-superpowers-plugin" tabindex="-1">Step 2: Install Superpowers Plugin <a class="header-anchor" href="#step-2-install-superpowers-plugin" aria-label="Permalink to &quot;Step 2: Install Superpowers Plugin&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/plugin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> superpowers@superpowers-marketplace</span></span></code></pre></div><p><strong>Why</strong></p><p>Download and install the Superpowers plugin from the marketplace you just registered.</p><p><strong>You should see</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>📦 Installing superpowers from superpowers-marketplace...</span></span>
<span class="line"><span>✅ Successfully installed superpowers</span></span></code></pre></div><hr><h3 id="step-3-verify-installation" tabindex="-1">Step 3: Verify Installation <a class="header-anchor" href="#step-3-verify-installation" aria-label="Permalink to &quot;Step 3: Verify Installation&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/help</span></span></code></pre></div><p><strong>Why</strong></p><p>Check if Superpowers commands are correctly loaded.</p><p><strong>You should see</strong> the following commands:</p><table tabindex="0"><thead><tr><th>Command</th><th>Function</th></tr></thead><tbody><tr><td><code>/superpowers:brainstorm</code></td><td>Interactive design refinement</td></tr><tr><td><code>/superpowers:write-plan</code></td><td>Create implementation plan</td></tr><tr><td><code>/superpowers:execute-plan</code></td><td>Batch execute plan</td></tr></tbody></table><p>If you see these three commands, installation is successful!</p><hr><h3 id="step-4-experience-your-first-command" tabindex="-1">Step 4: Experience Your First Command <a class="header-anchor" href="#step-4-experience-your-first-command" aria-label="Permalink to &quot;Step 4: Experience Your First Command&quot;">​</a></h3><p>Now try the core feature — let AI clarify requirements with you before writing code.</p><p>Enter:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">/superpowers:brainstorm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> want</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> to</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> a</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> comment</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> feature</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> to</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> the</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> blog</span></span></code></pre></div><p><strong>Why</strong></p><p>Trigger the brainstorming skill so AI asks questions first instead of writing code directly.</p><p><strong>You will see</strong>:</p><ol><li>AI won&#39;t write code directly</li><li>AI will ask you questions (e.g., &quot;What features should comments support? Is login required? Do you need likes?&quot;)</li><li>After you answer, AI will display the design in segments (200-300 words each, easy to digest)</li><li>Once design is confirmed, AI will save the design document to the <code>docs/plans/</code> directory</li></ol><p>This is the core of Superpowers — <strong>clarify first, then code</strong>.</p><hr><h2 id="checklist-✅" tabindex="-1">Checklist ✅ <a class="header-anchor" href="#checklist-✅" aria-label="Permalink to &quot;Checklist ✅&quot;">​</a></h2><p>Confirm all checkpoints pass:</p><ul><li>[ ] <code>/help</code> shows three commands: <code>/superpowers:brainstorm</code>, etc.</li><li>[ ] <code>/superpowers:brainstorm</code> command triggers (AI asks questions first, doesn&#39;t write code directly)</li><li>[ ] AI doesn&#39;t skip design and start coding directly</li></ul><p>If all pass, congratulations! You&#39;ve completed the Superpowers quick start!</p><hr><h2 id="troubleshooting-tips" tabindex="-1">Troubleshooting Tips <a class="header-anchor" href="#troubleshooting-tips" aria-label="Permalink to &quot;Troubleshooting Tips&quot;">​</a></h2><h3 id="commands-not-appearing" tabindex="-1">Commands Not Appearing <a class="header-anchor" href="#commands-not-appearing" aria-label="Permalink to &quot;Commands Not Appearing&quot;">​</a></h3><p><strong>Symptom</strong>: Superpowers commands not visible in <code>/help</code></p><p><strong>Solution</strong>:</p><ol><li>Confirm you entered <code>/superpowers:brainstorm</code> (colon, not space)</li><li>Try restarting Claude Code</li><li>Re-execute installation steps</li></ol><h3 id="ai-still-writes-code-directly" tabindex="-1">AI Still Writes Code Directly <a class="header-anchor" href="#ai-still-writes-code-directly" aria-label="Permalink to &quot;AI Still Writes Code Directly&quot;">​</a></h3><p><strong>Symptom</strong>: After using <code>/superpowers:brainstorm</code>, AI starts writing code directly</p><p><strong>Solution</strong>:</p><ul><li>This might be because your question is too simple, and AI thinks &quot;no design needed&quot;</li><li>Try a more complex task (e.g., &quot;Refactor user authentication system, add two-factor authentication&quot;)</li><li>Ensure you have the latest version: <code>/plugin update superpowers</code></li></ul><hr><h2 id="chapter-summary" tabindex="-1">Chapter Summary <a class="header-anchor" href="#chapter-summary" aria-label="Permalink to &quot;Chapter Summary&quot;">​</a></h2><p>In 5 minutes you completed:</p><ol><li>✅ Installed Superpowers plugin</li><li>✅ Verified commands are correctly loaded</li><li>✅ Experienced the first core feature (brainstorming)</li></ol><p><strong>Key Takeaways</strong>:</p><ul><li>Superpowers is not &quot;smarter AI,&quot; it&#39;s &quot;obedient AI&quot;</li><li>It ensures code quality through enforced workflows (design → plan → TDD → review)</li><li>Skills trigger automatically, no manual selection needed</li></ul><hr><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../installation/">Installation Guide</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>Complete installation steps for all three platforms</li><li>Manual configuration for OpenCode and Codex</li><li>Detailed troubleshooting methods</li></ul></blockquote>`,87)])])}const g=t(r,[["render",o]]);export{c as __pageData,g as default};
